@* Displays a single product as a card with image, name, price, rating, stock status, and add-to-cart *@

<div class="card product-card h-100" @onclick="HandleCardClick" role="button">
    <div class="product-image-placeholder d-flex align-items-center justify-content-center bg-light" style="height: 180px;">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title text-truncate" title="@Product.Name">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="card-text mb-2">
            <span class="text-warning">@GetStarRating(Product.Rating)</span>
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarRating(double rating)
    {
        int filled = (int)Math.Round(rating);
        int empty = 5 - filled;
        return new string('★', filled) + new string('☆', empty);
    }
}

@* Renders a responsive grid of ProductCard components *@

<div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
    @foreach (var product in Products)
    {
        <div class="col">
            <ProductCard Product="product"
                         OnProductSelected="OnProductSelected"
                         OnAddToCart="OnAddToCart" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = [];

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@* Sidebar filter controls: category checkboxes, price range, in-stock toggle *@

<div class="p-3 border rounded bg-light">
    <h5>Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-semibold">Category</label>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                           checked="@(_selectedCategories.Contains(category))"
                           @onchange="e => ToggleCategory(category, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Price Range</label>
        <div class="d-flex gap-2 align-items-center">
            <input type="number" class="form-control form-control-sm" placeholder="Min"
                   value="@_minPrice" @onchange="e => _minPrice = ParseDecimal(e.Value)" />
            <span>–</span>
            <input type="number" class="form-control form-control-sm" placeholder="Max"
                   value="@_maxPrice" @onchange="e => _maxPrice = ParseDecimal(e.Value)" />
        </div>
    </div>

    <div class="mb-3 form-check">
        <input class="form-check-input" type="checkbox" id="inStockOnly"
               checked="@_inStockOnly" @onchange="e => _inStockOnly = (bool)(e.Value ?? false)" />
        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    private HashSet<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFilterApplied.InvokeAsync(new ProductFilter(null, null, null, false));
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@* Toolbar with sort dropdown and result count label *@

<div class="d-flex justify-content-between align-items-center flex-wrap gap-2 mb-3">
    <div class="d-flex align-items-center gap-2">
        <label class="form-label mb-0 fw-semibold" for="sortSelect">Sort by:</label>
        <select id="sortSelect" class="form-select form-select-sm" style="width: auto;"
                value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A–Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>

    <span class="text-muted">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <text>Showing @start–@end of @TotalCount products</text>
        }
        else
        {
            <text>No products found</text>
        }
    </span>
</div>

@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "price_asc";
        await OnSortChanged.InvokeAsync(value);
    }
}

@* Pagination controls: Previous, numbered pages, Next *@

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-3">
        <ul class="pagination justify-content-center mb-0">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(CurrentPage - 1)" disabled="@(CurrentPage <= 1)">
                    Previous
                </button>
            </li>

            @foreach (var page in GetPageNumbers())
            {
                <li class="page-item @(page == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="() => GoToPage(page)">@page</button>
                </li>
            }

            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(CurrentPage + 1)" disabled="@(CurrentPage >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int CurrentPage { get; set; }

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => PageSize > 0 ? (int)Math.Ceiling((double)TotalCount / PageSize) : 1;

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    /// <summary>Shows up to 7 page buttons with ellipsis-style windowing.</summary>
    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 7;
        if (TotalPages <= maxVisible)
        {
            return Enumerable.Range(1, TotalPages);
        }

        int start = Math.Max(1, CurrentPage - maxVisible / 2);
        int end = start + maxVisible - 1;
        if (end > TotalPages)
        {
            end = TotalPages;
            start = end - maxVisible + 1;
        }
        return Enumerable.Range(start, end - start + 1);
    }
}

@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
    </div>
}

<div class="row">
    @* Left sidebar — ~25% width *@
    <div class="col-md-3 mb-3">
        <CatalogFilters Categories="_categories" OnFilterApplied="HandleFilterApplied" />
    </div>

    @* Main content — ~75% width *@
    <div class="col-md-9">
        <CatalogToolbar SortBy="@_sortBy"
                        TotalCount="@_totalCount"
                        Page="@_currentPage"
                        PageSize="@PageSize"
                        OnSortChanged="HandleSortChanged" />

        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_products.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products match your criteria. Try adjusting the filters.
            </div>
        }
        else
        {
            <ProductGrid Products="_products"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="_currentPage"
                               TotalCount="_totalCount"
                               PageSize="@PageSize"
                               OnPageChanged="HandlePageChanged" />
        }
    </div>
</div>

@code {
    private const int PageSize = 12;

    private List<Product> _products = [];
    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalCount;
    private bool _loading = true;
    private string? _error;

    /// <summary>Raised when a product card is clicked (not the Add to Cart button).</summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = LoadProductsAsync();
            await Task.WhenAll(categoriesTask, productsTask);
            _categories = await categoriesTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task LoadProductsAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            _products = result.Items;
            _totalCount = result.TotalCount;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _products = [];
            _totalCount = 0;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProductsAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — wire to a cart service when available
        return Task.CompletedTask;
    }
}

