            await Task.WhenAll(categoriesTask, productsTask);
            _categories = await categoriesTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task LoadProductsAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            _products = result.Items;
            _totalCount = result.TotalCount;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _products = [];
            _totalCount = 0;
        }
        finally
        {
            _loading = false;
        }
    }

